function isPublicRoute(path) {
  const publicRoutes = ["/health", "/api/users/login", "/api/users/register"];
  return publicRoutes.some((route) => path === route || path.startsWith(route + "/"));
}

async function authenticateRequest(request, env) {
  const authHeader = request.headers.get("Authorization");
  if (!authHeader || !authHeader.startsWith("Bearer ")) {
    return { authenticated: false };
  }

  const token = authHeader.substring(7);

  try {
    // Verify JWT using the AUTH service
    const verifyResponse = await env.AUTH_SERVICE.fetch(
      new Request("https://internal/verify", {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
          "X-Internal-Auth": await generateInternalToken(env),
        },
        body: JSON.stringify({ token }),
      })
    );

    if (!verifyResponse.ok) {
      return { authenticated: false };
    }

    const result = await verifyResponse.json();
    return {
      authenticated: true,
      userId: result.userId,
      role: result.role,
    };
  } catch {
    return { authenticated: false };
  }
}

async function generateInternalToken(env) {
  // HMAC-based internal service authentication
  const secret = env.INTERNAL_SECRET;
  const timestamp = Math.floor(Date.now() / 30000); // 30-second window
  const encoder = new TextEncoder();
  const key = await crypto.subtle.importKey(
    "raw",
    encoder.encode(secret),
    { name: "HMAC", hash: "SHA-256" },
    false,
    ["sign"]
  );
  const signature = await crypto.subtle.sign("HMAC", key, encoder.encode(`internal-${timestamp}`));
  return btoa(String.fromCharCode(...new Uint8Array(signature))) + "." + timestamp;
}

async function routeToService(service, originalRequest, internalHeaders, fullPath, prefix) {
  const servicePath = fullPath.substring(prefix.length) || "/";
  const url = new URL(`https://internal${servicePath}`);

  // Copy query parameters
  const originalUrl = new URL(originalRequest.url);
  originalUrl.searchParams.forEach((value, key) => {
    // Sanitize query parameters
    url.searchParams.set(sanitizeInput(key), sanitizeInput(value));
  });

  const init = {
    method: originalRequest.method,
    headers: internalHeaders,
  };

  if (originalRequest.method !== "GET" && originalRequest.method !== "HEAD") {
    init.body = originalRequest.body;
  }

  return service.fetch(new Request(url.toString(), init));
}

function sanitizeInput(input) {
  if (typeof input !== "string") return "";
  // Remove null bytes and control characters
  return input.replace(/[\x00-\x1f\x7f]/g, "").substring(0, 1000);
}


