async function verifyInternalAuth(request, env) {
  const token = request.headers.get("X-Internal-Auth");
  if (!token) return { valid: false };

  try {
    const [signatureB64, timestampStr] = token.split(".");
    const timestamp = parseInt(timestampStr);
    const currentWindow = Math.floor(Date.now() / 30000);

    // Allow current and previous window (60-second tolerance)
    if (Math.abs(currentWindow - timestamp) > 1) {
      return { valid: false };
    }

    const encoder = new TextEncoder();
    const key = await crypto.subtle.importKey(
      "raw",
      encoder.encode(env.INTERNAL_SECRET),
      { name: "HMAC", hash: "SHA-256" },
      false,
      ["verify"]
    );

    const signatureBytes = Uint8Array.from(atob(signatureB64), (c) => c.charCodeAt(0));
    const valid = await crypto.subtle.verify(
      "HMAC",
      key,
      signatureBytes,
      encoder.encode(`internal-${timestamp}`)
    );

    return { valid };
  } catch {
    return { valid: false };
  }
}

async function handleVerifyToken(request, env) {
  const { token } = await request.json();

  if (!token || typeof token !== "string") {
    return new Response(JSON.stringify({ error: "Invalid token format" }), {
      status: 400,
      headers: { "Content-Type": "application/json" },
    });
  }

  // Check if token is revoked
  const revoked = await env.TOKEN_KV.get(`revoked:${token}`);
  if (revoked) {
    return new Response(JSON.stringify({ error: "Token revoked" }), {
      status: 401,
      headers: { "Content-Type": "application/json" },
    });
  }

  try {
    // Verify JWT
    const parts = token.split(".");
    if (parts.length !== 3) {
      return new Response(JSON.stringify({ error: "Invalid token" }), {
        status: 401,
        headers: { "Content-Type": "application/json" },
      });
    }

    const [headerB64, payloadB64, signatureB64] = parts;

    const encoder = new TextEncoder();
    const key = await crypto.subtle.importKey(
      "raw",
      encoder.encode(env.JWT_SECRET),
      { name: "HMAC", hash: "SHA-256" },
      false,
      ["verify"]
    );

    const signatureBytes = Uint8Array.from(
      atob(signatureB64.replace(/-/g, "+").replace(/_/g, "/")),
      (c) => c.charCodeAt(0)
    );

    const valid = await crypto.subtle.verify(
      "HMAC",
      key,
      signatureBytes,
      encoder.encode(`${headerB64}.${payloadB64}`)
    );

    if (!valid) {
      return new Response(JSON.stringify({ error: "Invalid signature" }), {
        status: 401,
        headers: { "Content-Type": "application/json" },
      });
    }

    const payload = JSON.parse(atob(payloadB64.replace(/-/g, "+").replace(/_/g, "/")));

    // Check expiration
    if (payload.exp && payload.exp < Math.floor(Date.now() / 1000)) {
      return new Response(JSON.stringify({ error: "Token expired" }), {
        status: 401,
        headers: { "Content-Type": "application/json" },
      });
    }

    return new Response(
      JSON.stringify({
        userId: payload.sub,
        role: payload.role,
        exp: payload.exp,
      }),
      { headers: { "Content-Type": "application/json" } }
    );
  } catch {
    return new Response(JSON.stringify({ error: "Token verification failed" }), {
      status: 401,
      headers: { "Content-Type": "application/json" },
    });
  }
}

async function handleIssueToken(request, env) {
  const { userId, role, expiresIn } = await request.json();

  if (!userId || !role) {
    return new Response(JSON.stringify({ error: "userId and role required" }), {
      status: 400,
      headers: { "Content-Type": "application/json" },
    });
  }

  const now = Math.floor(Date.now() / 1000);
  const exp = now + (expiresIn || 3600); // Default 1 hour

  const header = { alg: "HS256", typ: "JWT" };
  const payload = {
    sub: userId,
    role,
    iat: now,
    exp,
    jti: crypto.randomUUID(),
  };

  const headerB64 = btoa(JSON.stringify(header)).replace(/=/g, "").replace(/\+/g, "-").replace(/\//g, "_");
  const payloadB64 = btoa(JSON.stringify(payload)).replace(/=/g, "").replace(/\+/g, "-").replace(/\//g, "_");

  const encoder = new TextEncoder();
  const key = await crypto.subtle.importKey(
    "raw",
    encoder.encode(env.JWT_SECRET),
    { name: "HMAC", hash: "SHA-256" },
    false,
    ["sign"]
  );

  const signature = await crypto.subtle.sign("HMAC", key, encoder.encode(`${headerB64}.${payloadB64}`));
  const signatureB64 = btoa(String.fromCharCode(...new Uint8Array(signature)))
    .replace(/=/g, "")
    .replace(/\+/g, "-")
    .replace(/\//g, "_");

  const token = `${headerB64}.${payloadB64}.${signatureB64}`;

  return new Response(JSON.stringify({ token, expiresAt: exp }), {
    headers: { "Content-Type": "application/json" },
  });
}

async function handleRevokeToken(request, env) {
  const { token } = await request.json();

  if (!token) {
    return new Response(JSON.stringify({ error: "Token required" }), {
      status: 400,
      headers: { "Content-Type": "application/json" },
    });
  }

  // Store revoked token with TTL matching max token lifetime
  await env.TOKEN_KV.put(`revoked:${token}`, "1", { expirationTtl: 86400 });

  return new Response(JSON.stringify({ success: true }), {
    headers: { "Content-Type": "application/json" },
  });
}


