async function hashPassword(password, salt) {
  const encoder = new TextEncoder();
  const keyMaterial = await crypto.subtle.importKey("raw", encoder.encode(password), "PBKDF2", false, ["deriveBits"]);
  const derivedBits = await crypto.subtle.deriveBits(
    {
      name: "PBKDF2",
      salt: encoder.encode(salt),
      iterations: 100000,
      hash: "SHA-256",
    },
    keyMaterial,
    256
  );
  return btoa(String.fromCharCode(...new Uint8Array(derivedBits)));
}

async function verifyPassword(password, storedHash, salt) {
  const hash = await hashPassword(password, salt);
  // Constant-time comparison
  if (hash.length !== storedHash.length) return false;
  let result = 0;
  for (let i = 0; i < hash.length; i++) {
    result |= hash.charCodeAt(i) ^ storedHash.charCodeAt(i);
  }
  return result === 0;
}

function sanitizeString(input) {
  return input.replace(/[<>&"']/g, (char) => {
    const entities = { "<": "&lt;", ">": "&gt;", "&": "&amp;", '"': "&quot;", "'": "&#x27;" };
    return entities[char] || char;
  });
}

async function verifyInternalAuth(request, env) {
  const token = request.headers.get("X-Internal-Auth");
  if (!token) return { valid: false };
  try {
    const [signatureB64, timestampStr] = token.split(".");
    const timestamp = parseInt(timestampStr);
    const currentWindow = Math.floor(Date.now() / 30000);
    if (Math.abs(currentWindow - timestamp) > 1) return { valid: false };
    const encoder = new TextEncoder();
    const key = await crypto.subtle.importKey("raw", encoder.encode(env.INTERNAL_SECRET), { name: "HMAC", hash: "SHA-256" }, false, ["verify"]);
    const signatureBytes = Uint8Array.from(atob(signatureB64), (c) => c.charCodeAt(0));
    const valid = await crypto.subtle.verify("HMAC", key, signatureBytes, encoder.encode(`internal-${timestamp}`));
    return { valid };
  } catch {
    return { valid: false };
  }
}

async function generateInternalToken(env) {
  const secret = env.INTERNAL_SECRET;
  const timestamp = Math.floor(Date.now() / 30000);
  const encoder = new TextEncoder();
  const key = await crypto.subtle.importKey("raw", encoder.encode(secret), { name: "HMAC", hash: "SHA-256" }, false, ["sign"]);
  const signature = await crypto.subtle.sign("HMAC", key, encoder.encode(`internal-${timestamp}`));
  return btoa(String.fromCharCode(...new Uint8Array(signature))) + "." + timestamp;
}


// ============================================
// Worker 4: Product Service (Internal Worker)
// File: product-service/src/index.js
// ============================================

export default {
  async fetch(request, env, ctx) {
    const authCheck = await verifyInternalAuth(request, env);
    if (!authCheck.valid) {
      return new Response(JSON.stringify({ error: "Forbidden" }), {
        status: 403,
        headers: { "Content-Type": "application/json" },
      });
    }

    const url = new URL(request.url);
    const path = url.pathname;
    const method = request.method;
    const userRole = request.headers.get("X-User-Role");
    const requestId = request.headers.get("X-Request-ID");

    try {
      // GET / - List products (public)
      if ((path === "/" || path === "") && method === "GET") {
        return await handleListProducts(url, env);
      }

      // POST / - Create product (admin only)
      if ((path === "/" || path === "") && method === "POST") {
        if (userRole !== "admin") {
          return new Response(JSON.stringify({ error: "Admin access required" }), {
            status: 403,
            headers: { "Content-Type": "application/json" },
          });
        }
        return await handleCreateProduct(request, env);
      }

      // GET /:id - Get product
      const productIdMatch = path.match(/^\/([a-zA-Z0-9-]+)$/);
      if (productIdMatch && method === "GET") {
        return await handleGetProduct(productIdMatch[1], env);
      }

      // PUT /:id - Update product (admin only)
      if (productIdMatch && method === "PUT") {
        if (userRole !== "admin") {
          return new Response(JSON.stringify({ error: "Admin access required" }), {
            status: 403,
            headers: { "Content-Type": "application/json" },
          });
        }
        return await handleUpdateProduct(productIdMatch[1], request, env);
      }

      // DELETE /:id - Delete product (admin only)
      if (productIdMatch && method === "DELETE") {
        if (userRole !== "admin") {
          return new Response(JSON.stringify({ error: "Admin access required" }), {
            status: 403,
            headers: { "Content-Type": "application/json" },
          });
        }
        return await handleDeleteProduct(productIdMatch[1], env);
      }

      return new Response(JSON.stringify({ error: "Not found" }), {
        status: 404,
        headers: { "Content-Type": "application/json" },
      });
    } catch (error) {
      console.error(`Product service error [${requestId}]:`, error.message);
      return new Response(JSON.stringify({ error: "Product service error" }), {
        status: 500,
        headers: { "Content-Type": "application/json" },
      });
    }
  },
};

async function handleListProducts(url, env) {
  const cursor = url.searchParams.get("cursor") || undefined;
  const limit = Math.min(parseInt(url.searchParams.get("limit") || "20"), 100);
  const category = url.searchParams.get("category");

  const prefix = category ? `product:cat:${sanitizeString(category)}:` : "product:id:";
  const list = await env.PRODUCTS_KV.list({ prefix, limit, cursor });

  const products = [];
  for (const key of list.keys) {
    const raw = await env.PRODUCTS_KV.get(key.name);
    if (raw) {
      const product = JSON.parse(raw);
      if (product.active) {
        products.push({
          id: product.id,
          name: product.name,
          description: product.description,
          price: product.price,
          category: product.category,
          inventory: product.inventory,
          createdAt: product.createdAt,
        });
      }
    }
  }

  return new Response(
    JSON.stringify({
      products,
      cursor: list.list_complete ? null : list.cursor,
      hasMore: !list.list_complete,
    }),
    { headers: { "Content-Type": "application/json" } }
  );
}

async function handleCreateProduct(request, env) {
  const { name, description, price, category, inventory } = await request.json();

  // Validate inputs
  if (!name || price === undefined || !category) {
    return new Response(JSON.stringify({ error: "Name, price, and category required" }), {
      status: 400,
      headers: { "Content-Type": "application/json" },
    });
  }

  if (typeof price !== "number" || price < 0 || price > 999999.99) {
    return new Response(JSON.stringify({ error: "Invalid price" }), {
      status: 400,
      headers: { "Content-Type": "application/json" },
    });
  }

  if (typeof inventory !== "undefined" && (typeof inventory !== "number" || inventory < 0)) {
    return new Response(JSON.stringify({ error: "Invalid inventory" }), {
      status: 400,
      headers: { "Content-Type": "application/json" },
    });
  }

  const productId = crypto.randomUUID();
  const product = {
    id: productId,
    name: sanitizeString(String(name).substring(0, 200)),
    description: sanitizeString(String(description || "").substring(0, 2000)),
    price: Math.round(price * 100) / 100, // Round to 2 decimal places
    category: sanitizeString(String(category).substring(0, 50)),
    inventory: inventory || 0,
    active: true,
    createdAt: Date.now(),
    updatedAt: Date.now(),
  };

  // Store with multiple indexes
  const productJson = JSON.stringify(product);
  await env.PRODUCTS_KV.put(`product:id:${productId}`, productJson);
  await env.PRODUCTS_KV.put(`product:cat:${product.category}:${productId}`, productJson);

  return new Response(JSON.stringify(product), {
    status: 201,
    headers: { "Content-Type": "application/json" },
  });
}

async function handleGetProduct(productId, env) {
  // Validate product ID format
  if (!/^[a-zA-Z0-9-]+$/.test(productId)) {
    return new Response(JSON.stringify({ error: "Invalid product ID" }), {
      status: 400,
      headers: { "Content-Type": "application/json" },
    });
  }

  const raw = await env.PRODUCTS_KV.get(`product:id:${productId}`);
  if (!raw) {
    return new Response(JSON.stringify({ error: "Product not found" }), {
      status: 404,
      headers: { "Content-Type": "application/json" },
    });
  }

  const product = JSON.parse(raw);
  return new Response(JSON.stringify(product), {
    headers: { "Content-Type": "application/json" },
  });
}

async function handleUpdateProduct(productId, request, env) {
  const raw = await env.PRODUCTS_KV.get(`product:id:${productId}`);
  if (!raw) {
    return new Response(JSON.stringify({ error: "Product not found" }), {
      status: 404,
      headers: { "Content-Type": "application/json" },
    });
  }

  const product = JSON.parse(raw);
  const updates = await request.json();

  const allowedFields = ["name", "description", "price", "category", "inventory", "active"];
  for (const field of allowedFields) {
    if (updates[field] !== undefined) {
      if (field === "price") {
        if (typeof updates.price !== "number" || updates.price < 0) continue;
        product.price = Math.round(updates.price * 100) / 100;
      } else if (field === "inventory") {
        if (typeof updates.inventory !== "number" || updates.inventory < 0) continue;
        product.inventory = Math.floor(updates.inventory);
      } else if (field === "active") {
        product.active = Boolean(updates.active);
      } else {
        product[field] = sanitizeString(String(updates[field]).substring(0, field === "description" ? 2000 : 200));
      }
    }
  }

  product.updatedAt = Date.now();

  const productJson = JSON.stringify(product);
  await env.PRODUCTS_KV.put(`product:id:${productId}`, productJson);
  await env.PRODUCTS_KV.put(`product:cat:${product.category}:${productId}`, productJson);

  return new Response(JSON.stringify(product), {
    headers: { "Content-Type": "application/json" },
  });
}

async function handleDeleteProduct(productId, env) {
  const raw = await env.PRODUCTS_KV.get(`product:id:${productId}`);
  if (!raw) {
    return new Response(JSON.stringify({ error: "Product not found" }), {
      status: 404,
      headers: { "Content-Type": "application/json" },
    });
  }

  const product = JSON.parse(raw);

  // Soft delete
  product.active = false;
  product.deletedAt = Date.now();

  const productJson = JSON.stringify(product);
  await env.PRODUCTS_KV.put(`product:id:${productId}`, productJson);
  await env.PRODUCTS_KV.put(`product:cat:${product.category}:${productId}`, productJson);

  return new Response(JSON.stringify({ success: true }), {
    headers: { "Content-Type": "application/json" },
  });
}

function sanitizeString(input) {
  return input.replace(/[<>&"']/g, (char) => {
    const entities = { "<": "&lt;", ">": "&gt;", "&": "&amp;", '"': "&quot;", "'": "&#x27;" };
    return entities[char] || char;
  });
}

