export default {
  async fetch(request, env, ctx) {
    const authCheck = await verifyInternalAuth(request, env);
    if (!authCheck.valid) {
      return new Response(JSON.stringify({ error: "Forbidden" }), {
        status: 403,
        headers: { "Content-Type": "application/json" },
      });
    }

    const url = new URL(request.url);
    const path = url.pathname;
    const method = request.method;
    const userId = request.headers.get("X-Authenticated-User");
    const userRole = request.headers.get("X-User-Role");

    try {
      // POST / - Create order
      if ((path === "/" || path === "") && method === "POST") {
        return await handleCreateOrder(userId, request, env, ctx);
      }

      // GET / - List user's orders
      if ((path === "/" || path === "") && method === "GET") {
        return await handleListOrders(userId, userRole, url, env);
      }

      // GET /:id - Get order details
      const orderIdMatch = path.match(/^\/([a-zA-Z0-9-]+)$/);
      if (orderIdMatch && method === "GET") {
        return await handleGetOrder(orderIdMatch[1], userId, userRole, env);
      }

      // PUT /:id/cancel - Cancel order
      const cancelMatch = path.match(/^\/([a-zA-Z0-9-]+)\/cancel$/);
      if (cancelMatch && method === "PUT") {
        return await handleCancelOrder(cancelMatch[1], userId, userRole, env, ctx);
      }

      return new Response(JSON.stringify({ error: "Not found" }), {
        status: 404,
        headers: { "Content-Type": "application/json" },
      });
    } catch (error) {
      console.error("Order service error:", error.message);
      return new Response(JSON.stringify({ error: "Order service error" }), {
        status: 500,
        headers: { "Content-Type": "application/json" },
      });
    }
  },
};

async function handleCreateOrder(userId, request, env, ctx) {
  if (!userId) {
    return new Response(JSON.stringify({ error: "Authentication required" }), {
      status: 401,
      headers: { "Content-Type": "application/json" },
    });
  }

  const { items, shippingAddress } = await request.json();

  if (!items || !Array.isArray(items) || items.length === 0) {
    return new Response(JSON.stringify({ error: "Items required" }), {
      status: 400,
      headers: { "Content-Type": "application/json" },
    });
  }

  if (items.length > 50) {
    return new Response(JSON.stringify({ error: "Too many items (max 50)" }), {
      status: 400,
      headers: { "Content-Type": "application/json" },
    });
  }

  if (!shippingAddress || !shippingAddress.street || !shippingAddress.city || !shippingAddress.country) {
    return new Response(JSON.stringify({ error: "Complete shipping address required" }), {
      status: 400,
      headers: { "Content-Type": "application/json" },
    });
  }

  // Validate and fetch product details via product service
  let totalAmount = 0;
  const orderItems = [];

  for (const item of items) {
    if (!item.productId || !item.quantity || item.quantity < 1 || item.quantity > 100) {
      return new Response(JSON.stringify({ error: `Invalid item: ${item.productId}` }), {
        status: 400,
        headers: { "Content-Type": "application/json" },
      });
    }

    const productResponse = await env.PRODUCT_SERVICE.fetch(
      new Request(`https://internal/${item.productId}`, {
        headers: {
          "X-Internal-Auth": await generateInternalToken(env),
          "X-User-Role": "admin", // Internal service can read products
        },
      })
    );

    if (!productResponse.ok) {
      return new Response(JSON.stringify({ error: `Product not found: ${item.productId}` }), {
        status: 400,
        headers: { "Content-Type": "application/json" },
      });
    }

    const product = await productResponse.json();

    if (!product.active) {
      return new Response(JSON.stringify({ error: `Product unavailable: ${product.name}` }), {
        status: 400,
        headers: { "Content-Type": "application/json" },
      });
    }

    if (product.inventory < item.quantity) {
      return new Response(
        JSON.stringify({ error: `Insufficient inventory for: ${product.name}` }),
        { status: 400, headers: { "Content-Type": "application/json" } }
      );
    }

    const itemTotal = Math.round(product.price * item.quantity * 100) / 100;
    totalAmount += itemTotal;

    orderItems.push({
      productId: product.id,
      productName: product.name,
      price: product.price,
      quantity: item.quantity,
      total: itemTotal,
    });
  }

  const orderId = crypto.randomUUID();
  const order = {
    id: orderId,
    userId,
    items: orderItems,
    totalAmount: Math.round(totalAmount * 100) / 100,
    shippingAddress: {
      street: sanitizeString(String(shippingAddress.street).substring(0, 200)),
      city: sanitizeString(String(shippingAddress.city).substring(0, 100)),
      state: sanitizeString(String(shippingAddress.state || "").substring(0, 100)),
      country: sanitizeString(String(shippingAddress.country).substring(0, 100)),
      postalCode: sanitizeString(String(shippingAddress.postalCode || "").substring(0, 20)),
    },
    status: "pending",
    createdAt: Date.now(),
    updatedAt: Date.now(),
  };

  // Store order
  const orderJson = JSON.stringify(order);
  await env.ORDERS_KV.put(`order:${orderId}`, orderJson);
  await env.ORDERS_KV.put(`user-order:${userId}:${orderId}`, orderJson);

  // Update inventory (fire and forget for each product)
  ctx.waitUntil(
    Promise.all(
      orderItems.map((item) =>
        env.PRODUCT_SERVICE.fetch(
          new Request(`https://internal/${item.productId}`, {
            method: "PUT",
            headers: {
              "Content-Type": "application/json",
              "X-Internal-Auth": generateInternalTokenSync(env),
              "X-User-Role": "admin",
            },
            body: JSON.stringify({
              inventory: -item.quantity, // This would need proper inventory management
            }),
          })
        ).catch(() => {})
      )
    )
  );

  // Send order confirmation notification
  ctx.waitUntil(
    env.NOTIFICATION_SERVICE.fetch(
      new Request("https://internal/send", {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
          "X-Internal-Auth": await generateInternalToken(env),
        },
        body: JSON.stringify({
          type: "order_confirmation",
          userId,
          orderId,
          totalAmount: order.totalAmount,
        }),
      })
    ).catch(() => {})
  );

  return new Response(JSON.stringify(order), {
    status: 201,
    headers: { "Content-Type": "application/json" },
  });
}

async function handleListOrders(userId, userRole, url, env) {
  const cursor = url.searchParams.get("cursor") || undefined;
  const limit = Math.min(parseInt(url.searchParams.get("limit") || "20"), 100);

  const prefix = userRole === "admin" ? "order:" : `user-order:${userId}:`;
  const list = await env.ORDERS_KV.list({ prefix, limit, cursor });

  const orders = [];
  for (const key of list.keys) {
    const raw = await env.ORDERS_KV.get(key.name);
    if (raw) {
      const order = JSON.parse(raw);
      orders.push({
        id: order.id,
        totalAmount: order.totalAmount,
        status: order.status,
        itemCount: order.items.length,
        createdAt: order.createdAt,
      });
    }
  }

  return new Response(
    JSON.stringify({
      orders,
      cursor: list.list_complete ? null : list.cursor,
      hasMore: !list.list_complete,
    }),
    { headers: { "Content-Type": "application/json" } }
  );
}

async function handleGetOrder(orderId, userId, userRole, env) {
  const raw = await env.ORDERS_KV.get(`order:${orderId}`);
  if (!raw) {
    return new Response(JSON.stringify({ error: "Order not found" }), {
      status: 404,
      headers: { "Content-Type": "application/json" },
    });
  }

  const order = JSON.parse(raw);

  // Authorization: users can only see their own orders
  if (userRole !== "admin" && order.userId !== userId) {
    return new Response(JSON.stringify({ error: "Not found" }), {
      status: 404,
      headers: { "Content-Type": "application/json" },
    });
  }

  return new Response(JSON.stringify(order), {
    headers: { "Content-Type": "application/json" },
  });
}

async function handleCancelOrder(orderId, userId, userRole, env, ctx) {
  const raw = await env.ORDERS_KV.get(`order:${orderId}`);
  if (!raw) {
    return new Response(JSON.stringify({ error: "Order not found" }), {
      status: 404,
      headers: { "Content-Type": "application/json" },
    });
  }

  const order = JSON.parse(raw);

  if (userRole !== "admin" && order.userId !== userId) {
    return new Response(JSON.stringify({ error: "Not found" }), {
      status: 404,
      headers: { "Content-Type": "application/json" },
    });
  }

  if (order.status !== "pending") {
    return new Response(JSON.stringify({ error: "Order cannot be cancelled" }), {
      status: 400,
      headers: { "Content-Type": "application/json" },
    });
  }

  order.status = "cancelled";
  order.cancelledAt = Date.now();
  order.updatedAt = Date.now();

  const orderJson = JSON.stringify(order);
  await env.ORDERS_KV.put(`order:${orderId}`, orderJson);
  await env.ORDERS_KV.put(`user-order:${order.userId}:${orderId}`, orderJson);

  // Notify user of cancellation
  ctx.waitUntil(
    env.NOTIFICATION_SERVICE.fetch(
      new Request("https://internal/send", {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
          "X-Internal-Auth": await generateInternalToken(env),
        },
        body: JSON.stringify({
          type: "order_cancelled",
          userId: order.userId,
          orderId,
        }),
      })
    ).catch(() => {})
  );

  return new Response(JSON.stringify(order), {
    headers: { "Content-Type": "application/json" },
  });
}

