export default {
  async fetch(request, env, ctx) {
    // Rate limiter uses a lighter auth check since it's called on every request
    const authCheck = await verifyInternalAuth(request, env);
    if (!authCheck.valid) {
      return new Response(JSON.stringify({ error: "Forbidden" }), {
        status: 403,
        headers: { "Content-Type": "application/json" },
      });
    }

    const url = new URL(request.url);

    if (url.pathname === "/check" && request.method === "POST") {
      return await handleRateLimitCheck(request, env);
    }

    return new Response(JSON.stringify({ error: "Not found" }), {
      status: 404,
      headers: { "Content-Type": "application/json" },
    });
  },
};

async function handleRateLimitCheck(request, env) {
  const { clientIP, userId, route } = await request.json();

  // Define rate limit tiers
  const rateLimits = {
    default: { requests: 100, windowSeconds: 60 },
    "/api/users/login": { requests: 10, windowSeconds: 60 },
    "/api/users/register": { requests: 5, windowSeconds: 300 },
    "/api/orders": { requests: 30, windowSeconds: 60 },
  };

  // Find matching rate limit config
  let config = rateLimits.default;
  for (const [pattern, limit] of Object.entries(rateLimits)) {
    if (pattern !== "default" && route.startsWith(pattern)) {
      config = limit;
      break;
    }
  }

  // Use IP + route as the rate limit key
  const identifier = userId || clientIP;
  const windowKey = Math.floor(Date.now() / (config.windowSeconds * 1000));
  const rateLimitKey = `rl:${identifier}:${route}:${windowKey}`;

  // Get current count from KV
  const currentRaw = await env.RATE_LIMIT_KV.get(rateLimitKey);
  const current = currentRaw ? parseInt(currentRaw) : 0;

  if (current >= config.requests) {
    const retryAfter = config.windowSeconds - Math.floor((Date.now() / 1000) % config.windowSeconds);
    return new Response(
      JSON.stringify({
        limited: true,
        retryAfter,
        limit: config.requests,
        remaining: 0,
      }),
      { headers: { "Content-Type": "application/json" } }
    );
  }

  // Increment counter
  await env.RATE_LIMIT_KV.put(rateLimitKey, String(current + 1), {
    expirationTtl: config.windowSeconds + 10, // Add buffer
  });

  return new Response(
    JSON.stringify({
      limited: false,
      limit: config.requests,
      remaining: config.requests - current - 1,
    }),
    { headers: { "Content-Type": "application/json" } }
  );
}

async function verifyInternalAuth(request, env) {
  const token = request.headers.get("X-Internal-Auth");
  if (!token) return { valid: false };
  try {
    const [signatureB64, timestampStr] = token.split(".");
    const timestamp = parseInt(timestampStr);
    const currentWindow = Math.floor(Date.now() / 30000);
    if (Math.abs(currentWindow - timestamp) > 1) return { valid: false };
    const encoder = new TextEncoder();
    const key = await crypto.subtle.importKey("raw", encoder.encode(env.INTERNAL_SECRET), { name: "HMAC", hash: "SHA-256" }, false, ["verify"]);
    const signatureBytes = Uint8Array.from(atob(signatureB64), (c) => c.charCodeAt(0));
    const valid = await crypto.subtle.verify("HMAC", key, signatureBytes, encoder.encode(`internal-${timestamp}`));
    return { valid };
  } catch {
    return { valid: false };
  }
}


